+				APIVersion: "v1",
+				Kind:       "SessionTemplate",
+				Metadata:   SessionTemplateMetadata{},
+				Spec:       SessionTemplateSpec{},
+			},
+			wantErr: true,
+		},
+		{
+			name: "missing apiVersion",
+			tmpl: &SessionTemplate{
+				Kind: "SessionTemplate",
+				Metadata: SessionTemplateMetadata{
+					Name: "no-version",
+				},
+				Spec: SessionTemplateSpec{},
+			},
+			wantErr: true,
+		},
+		{
+			name: "missing kind",
+			tmpl: &SessionTemplate{
+				APIVersion: "v1",
+				Metadata: SessionTemplateMetadata{
+					Name: "no-kind",
+				},
+				Spec: SessionTemplateSpec{},
+			},
+			wantErr: true,
+		},
